// Arbeitnow response: { data: [...jobs] }
const data = $input.item.json.data || [];
if (data.length === 0) return [];
return data.map(job => ({ json: { ...job, source_label: 'arbeitnow' } }));

// Remotive response: { jobs: [...jobs] }
const data = $input.item.json.jobs || [];
if (data.length === 0) return [];
return data.map(job => ({ json: { ...job, source_label: 'remotive' } }));

// RemoteOK returns an array: [0] = legal notice, [1+] = jobs.
// Skip index 0 and any items without id+title (safety check).
const raw = $input.item.json;
const items = Array.isArray(raw) ? raw : [];
if (items.length <= 1) return [];
return items
  .filter((job, i) => i > 0 && job.id && job.title)
  .map(job => ({ json: { ...job, source_label: 'remoteok' } }));

// Normalize job data from any API source into JobRadar's normalized_input shape.
// source_label is 'arbeitnow' | 'remotive' | 'remoteok' -- set by Flatten nodes.

const job = $input.item.json;
const source = job.source_label;

function stripHtml(html) {
  return (html || '').replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();
}

let title, companyName, location, jobTypes, tags, description, jobUrl, publishedAt;

if (source === 'arbeitnow') {
  title = job.title;
  companyName = job.company_name;
  location = job.location;
  jobTypes = job.job_types || [];
  tags = job.tags || [];
  description = stripHtml(job.description);
  jobUrl = job.url || ('https://www.arbeitnow.com/jobs/' + job.slug);
  publishedAt = job.created_at ? new Date(job.created_at * 1000).toISOString() : null;
} else if (source === 'remotive') {
  title = job.title;
  companyName = job.company_name;
  location = job.candidate_required_location;
  jobTypes = job.job_type ? [job.job_type] : [];
  tags = job.tags || [];
  description = stripHtml(job.description);
  jobUrl = job.url;
  publishedAt = job.publication_date || null;
} else if (source === 'remoteok') {
  title = job.title;
  companyName = job.company;
  location = job.location || 'Worldwide';
  jobTypes = [];
  tags = Array.isArray(job.tags) ? job.tags : [];
  description = stripHtml(job.description || '');
  jobUrl = job.url || job.apply_url;
  publishedAt = job.date || null;
} else if (source === 'jobicy_api') {
  title = job.jobTitle;
  companyName = job.companyName;
  location = job.jobGeo || 'Remote';
  jobTypes = job.jobType ? [job.jobType] : [];
  tags = typeof job.jobIndustry === 'string' ? job.jobIndustry.split(',').map(s => s.trim()).filter(Boolean) : [];
  description = stripHtml(job.jobDescription || '');
  jobUrl = job.url;
  publishedAt = job.pubDate || null;
} else if (source === 'himalayas_api') {
  title = job.title;
  companyName = (job.company && (job.company.name || job.company)) || '';
  location = Array.isArray(job.locationRestrictions) ? job.locationRestrictions.join(', ') : 'Remote';
  jobTypes = job.jobType ? [job.jobType] : [];
  tags = Array.isArray(job.skills) ? job.skills : (Array.isArray(job.tags) ? job.tags : []);
  description = stripHtml(job.description || job.descriptionHtml || '');
  jobUrl = job.applicationLink || job.url || job.applyLink || '';
  publishedAt = job.createdAt || job.publishedAt || null;
} else {
  throw new Error('Unknown source_label: ' + source);
}

const now = new Date().toISOString();
const rawText = [
  'Title: ' + (title || ''),
  'Company: ' + (companyName || ''),
  'Location: ' + (location || 'Not specified'),
  'Remote: Yes',
  'Job Types: ' + (jobTypes || []).join(', '),
  'Tags: ' + (tags || []).join(', '),
  '',
  'Job Description:',
  (description || '').substring(0, 7000)
].join('\n');

return [{
  json: {
    source_label: source,
    normalized_input: {
      input_source: 'scraped',
      source_detail: source + '_api',
      email_account_id: null,
      email_address: null,
      email_provider: null,
      subject: title || null,
      date: publishedAt || now,
      raw_text: rawText,
      raw_meta: {
        url: jobUrl,
        label: source + '-api'
      }
    }
  }
}];

